import React from "react";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import { useAuth } from "./hooks/useAuth";
import LoginPage from "./pages/LoginPage";
import HomePage from "./pages/HomePage";
import AcademicPage from "./pages/AcademicPage";
import FoodPage from "./pages/FoodPage";
import LaundryPage from "./pages/LaundryPage";
import ComplaintPage from "./pages/ComplaintPage";
import Navbar from "./components/Navbar";

function ProtectedLayout({ children }) {
  const { user } = useAuth();

  return (
    <div className="min-h-screen bg-gradient-to-b from-white/85 via-white/90 to-white/95">
      {/* Optional: Add background image with overlay */}
      <div
        className="fixed inset-0 opacity-5 pointer-events-none"
        style={{
          backgroundImage: `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%232563eb' fill-opacity='0.1'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`,
        }}
      />

      <Navbar user={user} />

      <main className="relative z-10 max-w-7xl mx-auto px-4 py-8">
        {children}
      </main>
    </div>
  );
}

export default function App() {
  const { user, login, logout, isLoading, error: authError } = useAuth();

  if (!user) {
    return <LoginPage onLogin={login} isLoading={isLoading} authError={authError} />;
  }

  return (
    <Router>
      <Routes>
        <Route
          path="/"
          element={
            <ProtectedLayout>
              <HomePage />
            </ProtectedLayout>
          }
        />
        <Route
          path="/academic"
          element={
            <ProtectedLayout>
              <AcademicPage />
            </ProtectedLayout>
          }
        />
        <Route
          path="/food"
          element={
            <ProtectedLayout>
              <FoodPage />
            </ProtectedLayout>
          }
        />
        <Route
          path="/laundry"
          element={
            <ProtectedLayout>
              <LaundryPage />
            </ProtectedLayout>
          }
        />
        <Route
          path="/complaint"
          element={
            <ProtectedLayout>
              <ComplaintPage />
            </ProtectedLayout>
          }
        />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </Router>
  );
}
